public class SoundManager : MonoBehaviour
{
    public static SoundManager Instance { get; private set; }

    [SerializeField] AudioSource bgmSource;
    [SerializeField] AudioSource sfxSource;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public void PlayBGM(AudioClip clip)
    {
        bgmSource.clip = clip;
        bgmSource.Play();
    }

    public void PlaySFX(AudioClip clip)
    {
        sfxSource.PlayOneShot(clip);
    }
}

public class PlayerController : MonoBehaviour
{
    public static int Hp;
    public static bool isDie;
    public static bool atkState;

    void Update()
    {
        if (isDie) return;

        // 첫 번째 터치: 이동
        if (Input.touchCount > 0)
        {
            Touch touch = Input.GetTouch(0);
            Vector3 touchPos = Camera.main.ScreenToWorldPoint(touch.position);
            touchPos.z = 0;
            transform.position = Vector3.Lerp(
                transform.position, touchPos, moveSpeed * Time.deltaTime);
        }

        // 두 번째 터치: 공격 라인
        if (Input.touchCount > 1 && atkState)
        {
            Touch attackTouch = Input.GetTouch(1);
            DrawAttackLine(attackTouch);
        }
    }

    public void DecreaseHp(int damage)
    {
        Hp -= damage;
        if (Hp <= 0) isDie = true;
    }
}

public class Stage1_Boss : MonoBehaviour
{
    [SerializeField] GameObject[] patterns;
    private int currentPhase = 0;

    IEnumerator BossRoutine()
    {
        while (!isDead)
        {
            yield return StartCoroutine(Phase1Pattern());
            yield return StartCoroutine(Phase2Pattern());
            yield return StartCoroutine(Phase3Pattern());
        }
    }

    IEnumerator Phase1Pattern()
    {
        // 패턴 1: 직선 공격
        PatternManager.Instance.SpawnPattern(patterns[0]);
        yield return new WaitForSeconds(2f);

        // 패턴 2: 부채꼴 공격
        PatternManager.Instance.SpawnPattern(patterns[1]);
        yield return new WaitForSeconds(1.5f);

        // 패턴 3: 원형 공격
        for (int i = 0; i < 8; i++)
        {
            float angle = i * 45f;
            SpawnCircularAttack(angle);
        }
        yield return new WaitForSeconds(3f);
    }
}

public class Damagable : MonoBehaviour
{
    [SerializeField] int damage = 1;
    [SerializeField] bool destroyOnHit = true;

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (other.CompareTag("Player"))
        {
            PlayerController player = other.GetComponent<PlayerController>();
            if (player != null)
            {
                player.DecreaseHp(damage);

                // 피격 이펙트
                ParticleManager.Instance.PlayHitEffect(
                    transform.position);

                // 피격 사운드
                SoundManager.Instance.PlaySFX(hitSound);

                if (destroyOnHit)
                    Destroy(gameObject);
            }
        }
    }
}

using Spine.Unity;

public class SpineAnimController : MonoBehaviour
{
    [SerializeField] SkeletonAnimation skeletonAnim;

    public void PlayAnimation(string animName, bool loop = false)
    {
        skeletonAnim.AnimationState.SetAnimation(0, animName, loop);
    }

    public void PlayAttackAnimation(int patternIndex)
    {
        string animName = $"attack_{patternIndex}";
        PlayAnimation(animName, false);
    }

    public void OnAnimationComplete(string animName)
    {
        if (animName.Contains("attack"))
        {
            PlayAnimation("idle", true);
        }
    }
}
